// Console and basic JS
console.log('Hello from comprehensive test!');
console.log('Math.PI:', Math.PI);
console.log('Array:', [1, 2, 3].map(x => x * 2));
console.log('Object:', {name: 'test', value: 42});

// Test web.sleep
console.log('Before sleep');
await web.sleep(100);
console.log('After 100ms sleep');
await web.sleep(200);
console.log('After 200ms sleep');

// Test web.fetch
console.log('Testing web.fetch...');
try {
  const result = await web.fetch('https://httpbin.org/get');
  console.log('Status:', result.status);
  console.log('OK:', result.ok);
  const body = JSON.parse(result.body);
  console.log('Origin:', body.origin);
} catch (e) {
  console.log('Fetch error:', e.message);
}

// Test web.storage
await web.storage.set('test_key', 'test_value');
const value = await web.storage.get('test_key');
console.log('Stored value:', value);
const keys = await web.storage.list();
console.log('Keys:', keys);
await web.storage.delete('test_key');
console.log('Deleted test_key');
const keysAfter = await web.storage.list();
console.log('Keys after delete:', keysAfter);

// Test web.url.parse
const parsed = await web.url.parse('https://example.com:8080/path?query=1#frag');
console.log('Parsed URL:', JSON.stringify(parsed));

// Test web.url.encode
const encoded = await web.url.encode({foo: 'bar', baz: 'qux'});
console.log('Encoded:', encoded);

// Test web.clipboard
const testText = 'Test clipboard content ' + Date.now();
await web.clipboard.write(testText);
const readText = await web.clipboard.read();
console.log('Written:', testText);
console.log('Read:', readText);
console.log('Match:', testText === readText ? '✅ YES' : '❌ NO');

// Test web.log
await web.log('Test log message from web.log');
await web.log({test: 'object logging'});
console.log('web.log called successfully');

// Test web.mock_async
const result = await web.mock_async('test-label');
console.log('mock_async result:', result);

// Test web.tab.query
const tabs = await web.tab.query({});
console.log('Tab count:', tabs.length);
if (tabs.length > 0) {
  console.log('First tab:', tabs[0].title);

  // Test snapshot
  const snapshot = await web.tab.snapshot(tabs[0].id);
  console.log('Snapshot length:', snapshot.length);

  // Test snapshot_data
  const data = await web.tab.snapshot_data(tabs[0].id);
  console.log('Snapshot data URL:', data.url);
}

// Test web.bookmarks
const bookmarks = await web.bookmarks.search({});
console.log('Bookmark count:', bookmarks.length);

// Test web.history
const history = await web.history.search({text: '', maxResults: 5});
console.log('History count:', history.length);

// Test web.cookies
const cookies = await web.cookies.list({});
console.log('Cookie count:', cookies.length);

// Test web.notifications
try {
  await web.notifications.create({type: 'basic', title: 'Test', message: 'Hello'});
  console.log('Notification created');
} catch (e) {
  console.log('Notification error:', e.message);
}

// Test fs operations
const testDir = '/tmp/test-' + Date.now();

// mkdir
await fs.mkdir(testDir);
console.log('Created dir:', testDir);

// write_text
await fs.write_text(testDir + '/hello.txt', 'Hello World!');
console.log('Wrote file');

// read_text
const content = await fs.read_text(testDir + '/hello.txt');
console.log('Read content:', content);

// exists
const exists = await fs.exists(testDir + '/hello.txt');
console.log('Exists:', exists);

// stat
const stat = await fs.stat(testDir + '/hello.txt');
console.log('Stat:', JSON.stringify(stat));

// list
const entries = await fs.list(testDir);
console.log('List:', JSON.stringify(entries));

// copy
await fs.copy(testDir + '/hello.txt', testDir + '/hello-copy.txt');
console.log('Copied file');

// read_range
const range = await fs.read_range(testDir + '/hello.txt', 0, 5);
console.log('Range (0-5):', range);

// hash
const hash = await fs.hash(testDir + '/hello.txt', 'sha256');
console.log('SHA256:', hash);

// append_text
await fs.append_text(testDir + '/hello.txt', ' Appended!');
const appended = await fs.read_text(testDir + '/hello.txt');
console.log('Appended:', appended);

// delete
await fs.delete(testDir + '/hello-copy.txt');
console.log('Deleted copy');

// cleanup
await fs.delete(testDir);
console.log('Cleaned up test dir');

// Test crypto
const message = 'Hello, World!';

console.log('SHA-256:', crypto.sha256(message));
console.log('MD5:', crypto.md5(message));
console.log('HMAC:', crypto.hmac_sha256('secret', message));

const hex = crypto.hex_encode(message);
console.log('Hex:', hex);
console.log('Decoded:', crypto.hex_decode(hex));

// Test chrome.tabs
const allTabs = await chrome.tabs.query({});
console.log('Total tabs:', allTabs.length);

if (allTabs.length > 0) {
  const tab = allTabs[0];
  console.log('First tab ID:', tab.id);

  // Get specific tab
  const gotTab = await chrome.tabs.get(tab.id);
  console.log('Got tab:', gotTab.title);
}

// Test chrome.storage.local
const testData = {
  test_string: 'hello',
  test_number: 42,
  test_array: [1, 2, 3],
  test_date: new Date().toISOString()
};

await chrome.storage.local.set(testData);
console.log('Set storage data');

const result = await chrome.storage.local.get(['test_string', 'test_number']);
console.log('Retrieved:', JSON.stringify(result));

await chrome.storage.local.remove('test_string');
console.log('Removed test_string');

await chrome.storage.local.clear();
console.log('Cleared all storage');

// Test chrome.bookmarks
const bookmarks = await chrome.bookmarks.search({});
console.log('Bookmarks:', bookmarks.length);

// Test chrome.history
const history = await chrome.history.search({text: '', maxResults: 5});
console.log('History items:', history.length);

// Test chrome.cookies
const cookies = await chrome.cookies.getAll({});
console.log('Cookies:', cookies.length);

// Test page APIs
const url = await page.url();
console.log('Current URL:', url);

const title = await page.title();
console.log('Page title:', title);

// Test snapshot
const snapshot = await page.snapshot();
console.log('Snapshot length:', snapshot.length);

// Test wait
await page.wait(100);
console.log('Waited 100ms');

// Test sidepanel APIs
const spUrl = await sidepanel.url();
console.log('Sidepanel URL:', spUrl);

const spTitle = await sidepanel.title();
console.log('Sidepanel title:', spTitle);

// Test wait
await sidepanel.wait(100);
console.log('Sidepanel waited 100ms');

// Test dom.snapshot
const domSnapshot = await dom.snapshot();
console.log('DOM snapshot length:', domSnapshot.length);

// Test runtime.inspect
const globals = runtime.inspect();
console.log('Global count:', globals.length);

const namespaces = globals
  .filter(g => g.type === 'object' && g.keys && g.keys.length > 0)
  .map(g => g.name);
console.log('Namespaces:', namespaces.join(', '));

// Test host.call
try {
  const result = await host.call('ping');
  console.log('host.call result:', result);
} catch (e) {
  console.log('host.call error:', e.message);
}

// Test chrome.alarms
try {
  await chrome.alarms.create('test-alarm', {delayInMinutes: 1});
  console.log('Alarm created');
  const alarms = await chrome.alarms.getAll();
  console.log('Alarms:', alarms.length);
} catch (e) {
  console.log('Alarms error:', e.message);
}

// Test chrome.notifications
try {
  const id = await chrome.notifications.create({
    type: 'basic',
    title: 'Test',
    message: 'Test notification'
  });
  console.log('Notification ID:', id);
} catch (e) {
  console.log('Notification error:', e.message);
}

// Test chrome.windows
const windows = await chrome.windows.getAll();
console.log('Windows:', windows.length);

// Test chrome.action
try {
  await chrome.action.setBadgeText({text: '42'});
  console.log('Badge text set');
  const text = await chrome.action.getBadgeText({});
  console.log('Badge text:', text);
} catch (e) {
  console.log('Action error:', e.message);
}

// Test chrome.contextMenus
try {
  await chrome.contextMenus.create({
    id: 'test-menu',
    title: 'Test Menu',
    contexts: ['all']
  });
  console.log('Context menu created');
} catch (e) {
  console.log('Context menu error:', e.message);
}

// Test chrome.sidePanel
try {
  await chrome.sidePanel.setOptions({
    enabled: true,
    path: 'sidepanel.html'
  });
  console.log('Sidepanel options set');
} catch (e) {
  console.log('Sidepanel error:', e.message);
}

// Test chrome.scripting
try {
  const results = await chrome.scripting.executeScript({
    target: {tabId: 1},
    func: () => document.title
  });
  console.log('Script result:', results[0]?.result);
} catch (e) {
  console.log('Scripting error:', e.message);
}

// Test chrome.runtime
console.log('Extension ID:', chrome.runtime.id);

try {
  const response = await chrome.runtime.sendMessage({action: 'ping'});
  console.log('Runtime response:', JSON.stringify(response));
} catch (e) {
  console.log('Runtime error:', e.message);
}
